CREATE TABLE IF NOT EXISTS "legal_orchestration_session" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "conversation_id" bigint NOT NULL,
    "user_id" bigint NOT NULL,
    "phase" varchar(32) NOT NULL DEFAULT 'INIT',
    "model_id" bigint DEFAULT NULL,
    "party_role" varchar(16) DEFAULT NULL,
    "audit_level" varchar(32) DEFAULT NULL,
    "audit_role_id" bigint DEFAULT NULL,
    "policy_json" clob DEFAULT NULL,
    "preview_opinion_json" clob DEFAULT NULL,
    "checkpoint_json" clob DEFAULT NULL,
    "remark" varchar(512) DEFAULT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "legal_orchestration_file_item" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "session_id" bigint NOT NULL,
    "infra_file_id" bigint NOT NULL,
    "file_name" varchar(255) NOT NULL,
    "status" varchar(32) NOT NULL DEFAULT 'REGISTERED',
    "suggested_type_id" bigint DEFAULT NULL,
    "confirmed_type_id" bigint DEFAULT NULL,
    "contract_id" bigint DEFAULT NULL,
    "sort" int NOT NULL DEFAULT 0,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "legal_agent_proposal" (
    "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "proposal_no" varchar(64) NOT NULL,
    "contract_id" bigint DEFAULT NULL,
    "conversation_id" bigint DEFAULT NULL,
    "user_id" bigint NOT NULL,
    "session_id" varchar(64) NOT NULL,
    "action" varchar(32) NOT NULL,
    "status" varchar(32) NOT NULL,
    "title" varchar(256) NOT NULL,
    "payload_json" clob NOT NULL,
    "expire_time" timestamp NOT NULL,
    "creator" varchar(64) DEFAULT '',
    "create_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updater" varchar(64) DEFAULT '',
    "update_time" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "deleted" bit NOT NULL DEFAULT FALSE,
    "tenant_id" bigint NOT NULL DEFAULT 0,
    PRIMARY KEY ("id")
);
